function findExecutable(executable) {
  const paths = process.env.PATH.split(':');
  for (const path of paths) {
    const fullPath = path + '/' + executable;
    if (fs.existsSync(fullPath) && fs.lstatSync(fullPath).isFile()) {
      return fullPath;
    }
  }
  return null;
}

