[sequelize, sequelize-cli, mysql2, dotenv]

```javascript
// Import required packages
require('dotenv').config();
const { Sequelize } = require('sequelize');
const sequelize = new Sequelize(process.env.DB_NAME, process.env.DB_USER, process.env.DB_PASSWORD, {
  host: process.env.DB_HOST,
  dialect: 'mysql',
});

// Define the User model
const User = sequelize.define('User', {
  name: {
    type: Sequelize.STRING,
    allowNull: false,
  },
  email: {
    type: Sequelize.STRING,
    unique: true,
    allowNull: false,
  },
});

// Establish the database connection
sequelize
  .authenticate()
  .then(() => {
    console.log('Database connected successfully');
  })
  .catch((err) => {
    console.error('Error connecting to database:', err);
  });

// Perform a simple query to find all users
User.findAll().then((users) => {
  console.log(users);
}).catch((err) => {
  console.error('Error fetching users:', err);
});
```

To use this code, you'll need to install the required packages using npm or yarn:

```bash
npm install sequelize sequelize-cli mysql2 dotenv
```

Then, create a .env file in the root of your project with your database credentials:

```bash
DB_NAME=your_database_name
DB_USER=your_database_user
DB_PASSWORD=your_database_password
DB_HOST=your_database_host
```

Finally, run the following command to create the database and the User model:

```bash
npx sequelize-cli db:create
npx sequelize-cli model:generate --name User --attributes name:string,email:string
```

