const crypto = require('crypto');

function pbkdf2(password, salt, iterations, keyLength, hashAlgorithm = 'sha256') {
  return new Promise((resolve, reject) => {
    crypto.pbkdf2(password, salt, iterations, keyLength, hashAlgorithm, (err, key) => {
      if (err) {
        reject(err);
      } else {
        resolve(key);
      }
    });
  });
}

function generateSalt() {
  return crypto.randomBytes(16);
}

function generateKey(password, salt, iterations, keyLength) {
  return pbkdf2(password, salt, iterations, keyLength);
}

// Example usage:
const salt = generateSalt();
const key = generateKey('mysecretpassword', salt, 100000, 32);

console.log('Salt:', salt.toString('hex'));
console.log('Key:', key.toString('hex'));
```

