```javascript
const camelcase = require('camelcase');
const _ = require('lodash');

function convertCamelCase(str, separator = '-') {
  const words = camelcase(str);
  return _.lowerCase(words).split(' ').join(separator);
}

console.log(convertCamelCase('helloWorld')); // hello-world
console.log(convertCamelCase('helloWorld', '_')); // hello_World
```
